import 'dart:convert';

class DependencyRecord {
  final String name;
  final String version;
  final String licenseExpression;
  final bool runtime;

  const DependencyRecord({
    required this.name,
    required this.version,
    required this.licenseExpression,
    required this.runtime,
  });
}

class ScanReportAdapter {
  List<DependencyRecord> decode(String payload) {
    final decoded = jsonDecode(payload);
    if (decoded is! Map<String, dynamic>) {
      throw const FormatException('scan report must be a JSON object');
    }

    final components = decoded['components'];
    if (components is! List) {
      return const <DependencyRecord>[];
    }

    final records = <DependencyRecord>[];
    for (final component in components) {
      if (component is! Map) {
        continue;
      }
      final name = component['name'];
      final version = component['version'];
      if (name is! String || version is! String) {
        continue;
      }
      final license = component['license'];
      records.add(
        DependencyRecord(
          name: name,
          version: version,
          licenseExpression: license is String ? license : 'UNKNOWN',
          runtime: component['runtime'] == true,
        ),
      );
    }
    return List<DependencyRecord>.unmodifiable(records);
  }
}

