import 'scan_report_adapter.dart';

class LicenseGate {
  final Set<String> allowedLicenses;

  LicenseGate(Iterable<String> allowedLicenses)
    : allowedLicenses = Set<String>.unmodifiable(allowedLicenses);

  bool allows(DependencyRecord record) {
    return allowedLicenses.contains(record.licenseExpression);
  }

  List<DependencyRecord> violations(Iterable<DependencyRecord> records) {
    return List<DependencyRecord>.unmodifiable(
      records.where((record) => record.runtime && !allows(record)),
    );
  }
}

