import '../lib/license_gate.dart';
import '../lib/scan_report_adapter.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  const payload = r'''
{
  "components": [
    {"name": "render-core", "version": "3.8.0", "license": "MIT", "runtime": true},
    {"name": "test-kit", "version": "1.1.0", "license": "UNKNOWN", "runtime": false}
  ]
}
''';

  final records = ScanReportAdapter().decode(payload);
  check(records.length == 2, 'reads legacy component records');
  check(records.first.name == 'render-core', 'keeps component coordinates');
  check(records.first.runtime, 'keeps runtime scope');

  final violations = LicenseGate(<String>{'MIT'}).violations(records);
  check(
    violations.isEmpty,
    'allows exact licenses and ignores non-runtime tools',
  );

  print('public tests passed');
}
